function cellKey(x: number, y: number): string {
  return `${x},${y}`;
}

export function evolve(aliveCells: [number, number][], steps: number): [number, number][] {
  if (steps === 0) return aliveCells;

  const alive = new Set(aliveCells.map(([x, y]) => cellKey(x, y)));

  return aliveCells.filter(([x, y]) => {
    let neighborCount = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (alive.has(cellKey(x + dx, y + dy))) neighborCount++;
      }
    }
    return neighborCount === 2 || neighborCount === 3;
  });
}

